# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messaging (with attachments and threaded replies), per-user performance
metrics, ratings, and exportable reports (CSV and PDF).

The public surface is intentionally small and deterministic so it can be driven
by an injectable clock. All entity-returning methods hand back deep copies so
callers can never mutate internal state by accident.

Standard library only.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Access level of a user within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report produced by the manager."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with the current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    status: TaskStatus = TaskStatus.NOT_STARTED
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Stores
#
# Each store owns one slice of state plus its indexes. Every store shares the
# *same* lock object as the manager so that compound, cross-store operations
# can be made atomic by acquiring the single lock at the manager level. Because
# the lock is reentrant, stores never need to lock independently; the manager
# always holds the lock for the duration of an operation.
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class UserStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._users: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}

    def add(self, user: User) -> None:
        self._users[user.id] = user
        self._by_username[user.username] = user.id
        self._by_email[user.email] = user.id

    def get(self, user_id: int) -> Optional[User]:
        return self._users.get(user_id)

    def all(self) -> List[User]:
        return [self._users[i] for i in sorted(self._users)]

    def username_owner(self, username: str) -> Optional[int]:
        return self._by_username.get(username)

    def email_owner(self, email: str) -> Optional[int]:
        return self._by_email.get(email)

    def rename_username(self, old: str, new: str, user_id: int) -> None:
        self._by_username.pop(old, None)
        self._by_username[new] = user_id

    def rename_email(self, old: str, new: str, user_id: int) -> None:
        self._by_email.pop(old, None)
        self._by_email[new] = user_id

    def remove(self, user_id: int) -> Optional[User]:
        user = self._users.pop(user_id, None)
        if user is None:
            return None
        self._by_username.pop(user.username, None)
        self._by_email.pop(user.email, None)
        return user


class ProjectStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._projects: Dict[int, Project] = {}

    def add(self, project: Project) -> None:
        self._projects[project.id] = project

    def get(self, project_id: int) -> Optional[Project]:
        return self._projects.get(project_id)

    def all(self) -> List[Project]:
        return [self._projects[i] for i in sorted(self._projects)]

    def owned_by(self, user_id: int) -> List[Project]:
        return [p for p in self._projects.values() if p.owner_id == user_id]

    def remove(self, project_id: int) -> Optional[Project]:
        return self._projects.pop(project_id, None)


class TaskStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._tasks: Dict[int, Task] = {}
        self._by_project: Dict[int, set] = {}
        self._by_assignee: Dict[int, set] = {}

    def add(self, task: Task) -> None:
        self._tasks[task.id] = task
        self._by_project.setdefault(task.project_id, set()).add(task.id)
        if task.assignee_id is not None:
            self._by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def get(self, task_id: int) -> Optional[Task]:
        return self._tasks.get(task_id)

    def all(self) -> List[Task]:
        return [self._tasks[i] for i in sorted(self._tasks)]

    def by_project(self, project_id: int) -> List[Task]:
        ids = self._by_project.get(project_id, set())
        return [self._tasks[i] for i in sorted(ids)]

    def by_assignee(self, user_id: int) -> List[Task]:
        ids = self._by_assignee.get(user_id, set())
        return [self._tasks[i] for i in sorted(ids)]

    def set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None and old in self._by_assignee:
            self._by_assignee[old].discard(task.id)
            if not self._by_assignee[old]:
                del self._by_assignee[old]
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._by_assignee.setdefault(new_assignee, set()).add(task.id)

    def remove(self, task_id: int) -> Optional[Task]:
        task = self._tasks.pop(task_id, None)
        if task is None:
            return None
        bucket = self._by_project.get(task.project_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                del self._by_project[task.project_id]
        if task.assignee_id is not None:
            abucket = self._by_assignee.get(task.assignee_id)
            if abucket is not None:
                abucket.discard(task_id)
                if not abucket:
                    del self._by_assignee[task.assignee_id]
        return task


class MessageStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._messages: Dict[int, Message] = {}
        self._by_project: Dict[int, set] = {}
        self._by_task: Dict[int, set] = {}

    def add(self, message: Message) -> None:
        self._messages[message.id] = message
        if message.project_id is not None:
            self._by_project.setdefault(message.project_id, set()).add(message.id)
        if message.task_id is not None:
            self._by_task.setdefault(message.task_id, set()).add(message.id)

    def get(self, message_id: int) -> Optional[Message]:
        return self._messages.get(message_id)

    def by_project(self, project_id: int) -> List[Message]:
        ids = self._by_project.get(project_id, set())
        return [self._messages[i] for i in sorted(ids)]

    def by_task(self, task_id: int) -> List[Message]:
        ids = self._by_task.get(task_id, set())
        return [self._messages[i] for i in sorted(ids)]

    def remove(self, message_id: int) -> Optional[Message]:
        message = self._messages.pop(message_id, None)
        if message is None:
            return None
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    del self._by_project[message.project_id]
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    del self._by_task[message.task_id]
        return message


class PerformanceStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, set] = {}

    def add(self, rating: Rating) -> None:
        self._ratings[rating.id] = rating
        self._by_ratee.setdefault(rating.ratee_id, set()).add(rating.id)

    def for_ratee(self, user_id: int) -> List[Rating]:
        ids = self._by_ratee.get(user_id, set())
        return [self._ratings[i] for i in sorted(ids)]


class ReportStore(_BaseStore):
    """Stateless formatter for report dictionaries (CSV and PDF)."""

    def export_csv(self, report: dict) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_average",
                "rating_count",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in columns])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(
                ["task_id", "title", "status", "assignee_id", "deadline", "overdue"]
            )
            for row in report.get("tasks", []):
                writer.writerow(
                    [
                        row.get("task_id", ""),
                        row.get("title", ""),
                        row.get("status", ""),
                        row.get("assignee_id", ""),
                        row.get("deadline", ""),
                        row.get("overdue", ""),
                    ]
                )

        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["project_name", report.get("project_name", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status_" + str(status), count])

        else:
            # Generic fallback: flatten scalar entries.
            writer.writerow(["key", "value"])
            for key, value in report.items():
                if isinstance(value, (str, int, float, bool)) or value is None:
                    writer.writerow([key, value])

        return buffer.getvalue()

    def export_pdf(self, report: dict) -> bytes:
        return _render_pdf(_flatten_report_to_lines(report))


# ---------------------------------------------------------------------------
# PDF rendering (minimal but spec-valid single-page document)
# ---------------------------------------------------------------------------
def _flatten_report_to_lines(report: dict) -> List[str]:
    lines: List[str] = []
    rtype = report.get("report_type", "report")
    lines.append("Report: {0}".format(rtype))
    for key, value in report.items():
        if key == "report_type":
            continue
        if isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_val in value.items():
                lines.append("  {0}: {1}".format(sub_key, sub_val))
        elif isinstance(value, list):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
            for item in value:
                if isinstance(item, dict):
                    lines.append(
                        "  - "
                        + ", ".join(
                            "{0}={1}".format(k, v) for k, v in item.items()
                        )
                    )
                else:
                    lines.append("  - {0}".format(item))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _render_pdf(lines: List[str]) -> bytes:
    """Render text lines into a minimal, valid PDF document."""

    def escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        )

    if not lines:
        lines = [""]

    content_ops = ["BT", "/F1 12 Tf", "14 TL", "50 750 Td"]
    for index, line in enumerate(lines):
        text = escape(str(line))[:200]
        if index == 0:
            content_ops.append("({0}) Tj".format(text))
        else:
            content_ops.append("T* ({0}) Tj".format(text))
    content_ops.append("ET")
    content = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray()
    out += b"%PDF-1.4\n"
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_pos = len(out)
    size = len(objects) + 1
    out += b"xref\n"
    out += b"0 " + str(size).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n"
    out += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n"
    out += str(xref_pos).encode("ascii") + b"\n"
    out += b"%%EOF\n"
    return bytes(out)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates all collaboration entities behind a single shared lock."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceStore(self._lock)
        self.reports = ReportStore(self._lock)

    # -- internal helpers ---------------------------------------------------
    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    def _require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email: str) -> None:
        if not isinstance(email, str) or not email.strip():
            raise ValidationError("email must be a non-empty string")
        if "@" not in email:
            raise ValidationError("email must contain '@'")

    @staticmethod
    def _copy(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _copy_list(objs) -> list:
        return [copy.deepcopy(o) for o in objs]

    # -- user management ----------------------------------------------------
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username must be a non-empty string")
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if self.users.username_owner(username) is not None:
                raise DuplicateError("username already in use")
            if self.users.email_owner(email) is not None:
                raise DuplicateError("email already in use")
            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.add(user)
            return self._copy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return self._copy_list(self.users.all())

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be a non-empty string")
                owner = self.users.username_owner(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")

            if email is not None:
                self._validate_email(email)
                owner = self.users.email_owner(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                self.users.rename_username(user.username, username, user_id)
                user.username = username
            if email is not None and email != user.email:
                self.users.rename_email(user.email, email, user_id)
                user.email = email
            if role is not None:
                user.role = role

            return self._copy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            self._require_user(user_id)
            if self.projects.owned_by(user_id):
                raise ConflictError("user owns one or more projects")
            for task in self.tasks.by_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")
            self.users.remove(user_id)

    # -- project management -------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")
            self._require_user(owner_id)
            project = Project(
                id=self._next_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._now(),
            )
            self.projects.add(project)
            return self._copy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return self._copy_list(self.projects.all())

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name must be a non-empty string")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description

            return self._copy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)
            for task in list(self.tasks.by_project(project_id)):
                for message in list(self.messages.by_task(task.id)):
                    self.messages.remove(message.id)
                self.tasks.remove(task.id)
            for message in list(self.messages.by_project(project_id)):
                self.messages.remove(message.id)
            self.projects.remove(project_id)

    # -- task management ----------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be a non-empty string")
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")
            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                assignee_id=assignee_id,
                deadline=deadline,
                status=TaskStatus.NOT_STARTED,
                created_at=self._now(),
            )
            self.tasks.add(task)
            return self._copy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            return self._copy_list(self.tasks.by_project(project_id))

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            return self._copy_list(self.tasks.by_assignee(user_id))

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self.tasks.set_assignee(task, assignee_id)
            return self._copy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self.tasks.set_assignee(task, new_assignee_id)
            return self._copy(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self.tasks.set_assignee(task, None)
            return self._copy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._copy(task)

    # -- messaging ----------------------------------------------------------
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[list] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = list(attachments) if attachments else []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError(
                    "message must have a body or at least one attachment"
                )

            now = self._now()
            built_attachments = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages.add(message)
            return self._copy(message)

    def _build_attachment(
        self, filename: str, data: bytes, uploaded_by: int, uploaded_at: datetime
    ) -> Attachment:
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("attachment filename must be a non-empty string")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=uploaded_at,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            body_text = new_body if isinstance(new_body, str) else ""
            if not body_text.strip() and not message.attachments:
                raise ValidationError(
                    "message must have a body or at least one attachment"
                )
            message.body = body_text
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments to a message"
                )
            attachment = self._build_attachment(
                filename, data, uploader_id, self._now()
            )
            message.attachments.append(attachment)
            return self._copy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            return self._copy_list(self.messages.by_project(project_id))

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            return self._copy_list(self.messages.by_task(task_id))

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            self.messages.remove(message_id)

    # -- performance --------------------------------------------------------
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.by_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self.tasks.by_assignee(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.add(rating)
            return self._copy(rating)

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance.for_ratee(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": self._copy_list(ratings),
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.by_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self.performance.for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports ------------------------------------------------------------
    def _task_summary(self, task: Task, now: datetime) -> dict:
        overdue = (
            task.deadline is not None
            and task.status != TaskStatus.COMPLETED
            and task.deadline < now
        )
        return {
            "task_id": task.id,
            "title": task.title,
            "status": task.status.value,
            "assignee_id": task.assignee_id,
            "deadline": task.deadline.isoformat() if task.deadline else "",
            "overdue": overdue,
        }

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            project = self._require_project(project_id)
            tasks = self.tasks.by_project(project_id)
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.status != TaskStatus.COMPLETED
                and task.deadline < now
            )
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                stats = per_assignee.setdefault(
                    task.assignee_id,
                    {
                        "total": 0,
                        "completed": 0,
                        "in_progress": 0,
                        "not_started": 0,
                    },
                )
                stats["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    stats["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    stats["in_progress"] += 1
                else:
                    stats["not_started"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project.id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
                "tasks": [self._task_summary(task, now) for task in tasks],
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped_tasks = self.tasks.by_project(project_id)
            else:
                scoped_tasks = self.tasks.all()

            tasks_by_user: Dict[int, List[Task]] = {}
            for task in scoped_tasks:
                if task.assignee_id is None:
                    continue
                tasks_by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(tasks_by_user):
                user = self.users.get(user_id)
                user_tasks = tasks_by_user[user_id]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                )
                durations = self._completion_durations(user_tasks)
                avg_time = sum(durations) / len(durations) if durations else None
                ratings = self.performance.for_ratee(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username if user else "",
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": (completed / total) if total else 0.0,
                        "average_completion_time": avg_time,
                        "rating_average": rating_average,
                        "rating_count": rating_count,
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            user = self.users.get(user_id)
            tasks = self.tasks.by_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None
            ratings = self.performance.for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            now = self._now()
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username if user else "",
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [self._task_summary(task, now) for task in tasks],
            }

    def export_report(self, report: dict, fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dictionary")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self.reports.export_csv(report)
        return self.reports.export_pdf(report)


